content:
/* Token usage bar */
  #token-bar{height:3px;background:var(--border);position:relative;overflow:hidden}
  #token-bar .fill{height:100%;background:var(--accent);transition:width .3s;width:0}
  #token-bar .fill.warn{background:#d29922}
  #token-bar .fill.crit{background:var(--err)}
  #token-info{font-size:11px;color:var(--dim);padding:2px 20px 0;text-align:right}

  /* Continue button */
  .continue-bar{display:flex;justify-content:center;padding:4px 0}
  .continue-bar button{background:var(--accent);color:#fff;border:none;border-radius:6px;padding:6px 20px;font-size:13px;cursor:pointer;font-weight:600}
  .continue-bar button:hover{opacity:.9}
